---资源请求器， 资源和实际使用对象之间的 引用关联
---资源引用计数的实践者
---@class LxResRequester
local LxResRequester = classX("LxResRequester", nil)

------------------------------------------------------------------------
local AssetLoadType = AssetLoadType

------------------------------------------------------------------------
function LxResRequester:Initialize(id, loadType, assetPath, assetType, callBack)
    self._id = id
    self._loadType = loadType
    self._assetPath = assetPath
    self._assetType = assetType
    self._callback = callBack

    ---@type LxAssetData
    self._assetData = nil

    if LOG_INFO_ENABLED then
        if string.isempty(assetPath) then
            printInfoNR("错误的用法， 资源的路径为 null")
        end
    end
end

function LxResRequester:SetSceneModeParam(loadSceneMode, suspendLoad, priority)
    self._loadSceneMode = loadSceneMode
    self._suspendLoad = suspendLoad
    self._priority = priority
end

function LxResRequester:GetAssetType()
    return self._assetType
end

function LxResRequester:GetAssetPath()
    return self._assetPath
end

function LxResRequester:GetId()
    return self._id
end

---@param assetData LxAssetData
function LxResRequester:SetAssetData(assetData)
    self._assetData = assetData
    assetData:AddRef()
end

function LxResRequester:StartRequester()
    local loadType = self._loadType

    if loadType == AssetLoadType.Asset then
        MgrCenter.ResourceMgr:LoadAssetAsync(self._assetPath, self._assetType, self)
    elseif loadType == AssetLoadType.AllAssets then
        MgrCenter.ResourceMgr:LoadAllAssetsAsync(self._assetPath, self._assetType, self)
    elseif loadType == AssetLoadType.SubAssets then
        MgrCenter.ResourceMgr:LoadSubAssetsAsync(self._assetPath, self._assetType, self)
    elseif loadType == AssetLoadType.RawFile then
        MgrCenter.ResourceMgr:LoadRawFileAsync(self._assetPath, self._assetType, self)
    elseif loadType == AssetLoadType.Scene then
        MgrCenter.ResourceMgr:LoadSceneAsync(self._assetPath, self._loadSceneMode, self._suspendLoad, self._priority, self)
    end
end

function LxResRequester:Dispose()
    if self:IsDisposed() then return end

    if self._assetData ~= nil and not self._assetData:IsDispose() then
        self._assetData:Release()
    end

    MgrCenter.ResourceMgr:RemoveRequester(self)

    self._callback = nil
    self._assetData = nil

    self._isDisposed = true
end

function LxResRequester:IsDisposed()
    return self._isDisposed
end

function LxResRequester:InvokeComplete()
    if self:IsDisposed() then return end
    
    self._isDone = true
    if self._callback ~= nil then
        self._callback(self._assetData and self._assetData.asset or nil , self._assetPath, self)
    end
end

function LxResRequester:IsDone()
    return self._isDone
end

return LxResRequester